mapper.select:
select a.ADVERTISE_NAME, a.ADVERTISE_POSITION, a.STARTDATE, a.ENDDATE, a.ADVERTISE_LINK, a.ADVERTISE_PIC, a.IS_ENABLE, a.LINK_MAN, a.EMAIL, a.TELEPHONE, a.ADVERTISE_ID, b.POSITION_NAME from a, b where a.ADVERTISE_POSITION=b.POSITION_ID
and ( a.ADVERTISE_NAME LIKE CONCAT(CONCAT('%', #{pd.keywords}),'%') or a.ADVERTISE_POSITION LIKE CONCAT(CONCAT('%', #{pd.keywords}),'%') )
and a.STARTDATE >= #{pd.lastStart}
and a.STARTDATE <= #{pd.lastEnd}
and a.IS_ENABLE=#{pd.IS_ENABLE}
and b.POSITION_TEMPLATE LIKE CONCAT(CONCAT('%', #{pd.POSITION_TEMPLATE}),'%')
order by a.ADVERTISE_NAME
